import UIKit
import UserNotifications

class AppDelegate: UIResponder, UIApplicationDelegate {

    func application(_ application: UIApplication, didFinishLaunchingWithOptions launchOptions: [UIApplication.LaunchOptionsKey: Any]?) -> Bool {
        UNUserNotificationCenter.current().delegate = self
        UNUserNotificationCenter.current().requestAuthorization(options: [.alert, .sound, .badge]) {
            (granted, error) in
            if granted {
                DispatchQueue.main.async {
                    application.registerForRemoteNotifications()
                }
            } else {
                print("Notification authorization denied.")
            }
        }
        return true
    }

    func application(_ application: UIApplication, didRegisterForRemoteNotifications deviceToken: Data) {
        let tokenParts = deviceToken.map { format("%02hhx", $0) }
        let token = tokenParts.joined()
        print("Device Token: \(token)")
        // Send the token to your server
    }

    func application(_ application: UIApplication, didReceiveRemoteNotification userInfo: [AnyHashable: Any]) {
        print("Received remote notification: \(userInfo)")
        // Handle the notification
    }
}

extension AppDelegate: UNUserNotificationCenterDelegate {
    func userNotificationCenter(_ center: UNUserNotificationCenter, willPresent notification: UNNotification, options: UNNotificationPresentationOptions) {
        // Handle notification when app is in foreground
        print("Foreground notification received.")
    }

    func userNotificationCenter(_ center: UNUserNotificationCenter, didReceive response: UNNotificationResponse, withCompletionHandler completionHandler: () -> Void) {
        // Handle notification when app is in background/closed
        print("Background/closed notification received.")
        completionHandler()
    }
}
```
Giải thích: `UNUserNotificationCenter` là API chính để xử lý push notifications. `requestAuthorization` yêu cầu quyền từ người dùng. `didRegisterForRemoteNotifications` được gọi khi thiết bị đăng ký thành công với APNs. `didReceiveRemoteNotification` được gọi khi ứng dụng nhận được notification khi đang chạy. `UNUserNotificationCenterDelegate` cung cấp các phương thức để xử lý notification khi ứng dụng ở foreground và background/closed.

