import StoreKit
import SwiftUI

class StoreManager: ObservableObject {
    @Published var products: [Product] = []
    @Published var purchaseStatus: PurchaseStatus = .notPurchased

    private var productIDs: Set<String> = ["com.example.premiumfeature"]

    init() {
        fetchProducts()
    }

    func fetchProducts() {
        let request = ProductQuery.request(for: productIDs)
        request.delegate = self
    }

    func purchaseProduct() {
        guard let product = products.first else { return }
        Purchase.request(for: product) { result in
            switch result {
            case .success(let purchase):
                self.purchaseStatus = .purchased
                print("Purchase successful: \(purchase)")
            case .failure(let error):
                self.purchaseStatus = .failed
                print("Purchase failed: \(error)")
            }
        }
    }
}

enum PurchaseStatus { case notPurchased, purchased, failed }

extension StoreManager: ProductQueryDelegate {
    func productQuery(_ query: ProductQuery, didFind products: [Product]) {
        self.products = products
    }

    func productQuery(_ query: ProductQuery, didFinishWithError error: Error?) {
        if let error = error {
            print("Error fetching products: \(error)")
        }
    }
}

struct ContentView: View {
    @ObservedObject var storeManager: StoreManager

    var body: some View {
        VStack {
            if storeManager.products.isEmpty {
                Text("Loading products...")
            } else {
                Text("Product Name: \(storeManager.products[0].displayName)")
                Text("Price: \(storeManager.products[0].price)")
                Button("Purchase") {
                    storeManager.purchaseProduct()
                }
            }

            Text("Purchase Status: \(storeManager.purchaseStatus)")
        }
    }
}
```
Giải thích: `ProductQuery` được sử dụng để tìm kiếm các sản phẩm có sẵn. `Purchase.request` được sử dụng để bắt đầu giao dịch mua. `PurchaseStatus` theo dõi trạng thái của giao dịch mua.  Quan trọng: Cần cấu hình App Store Connect và tạo các product ID trước khi sử dụng code này.  Cần xử lý các trường hợp lỗi và xác minh giao dịch trên server để đảm bảo an toàn.
